using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: happy paths ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_StoresItemsOnOrder()
    {
        var items = CreateItems(("Widget", 10m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreSame(items, order.Items);
    }

    // --- CreateOrder: total calculation ---

    [TestMethod]
    public void CreateOrder_SingleItem_CalculatesTotalAsPriceTimesQuantity()
    {
        var items = CreateItems(("Widget", 25.50m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsTotalsAcrossAllItems()
    {
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 4));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
    }

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-unknown");

        Assert.IsNotNull(result);
        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_OneOrder_ReturnsSingleMatch()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        var single = Assert.ContainsSingle(result);
        Assert.AreSame(created, single);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        var order1 = _service.CreateOrder("cust-1", CreateItems(("A", 5m, 1)));
        var order2 = _service.CreateOrder("cust-1", CreateItems(("B", 10m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 15m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, result);
        Assert.Contains(order1, result);
        Assert.Contains(order2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_DoesNotReturnOtherCustomerOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 5m, 1)));
        var otherOrder = _service.CreateOrder("cust-2", CreateItems(("B", 10m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.DoesNotContain(otherOrder, result);
    }
}

